import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';

@Injectable({
  providedIn: 'root'
})
export class ChessAgentService {
  // Remplace l'URL par l'adresse de ton API FastAPI en local
  private baseUrl = 'http://localhost:8000';

  constructor(private http: HttpClient) {}

  /**
   * Analyse la position FEN actuelle via le moteur d'échecs/IA
   */
  analyzePosition(fen: string): Observable<any> {
    return this.http.post(`${this.baseUrl}/analyze`, { fen });
  }

  /**
   * Envoie un message au chat de l'assistant en lui fournissant le contexte (FEN)
   */
  sendChatMessage(message: string, fen: string): Observable<any> {
    return this.http.post(`${this.baseUrl}/chat`, { 
      message: message, 
      fen: fen 
    });
  }
}
